// Extract external attendees and prepare meeting data
const input = $input.first().json;
const webhookData = input.webhookData || input.body || input;

// Get external attendees only
const externalAttendees = (webhookData.calendar_invitees || []).filter(
  invitee => invitee.is_external === true
);

if (externalAttendees.length === 0) {
  return [];
}

// Helper: Format date as DD/MM/YYYY
function formatDate(isoString) {
  if (!isoString) return new Date().toLocaleDateString('en-GB');
  const date = new Date(isoString);
  return date.toLocaleDateString('en-GB');
}

// Helper: Strip markdown links but keep text
function stripLinks(text) {
  if (!text) return '';
  return text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');
}

// Helper: Get brief summary (just the meeting purpose - first paragraph)
function getBriefSummary(markdown) {
  if (!markdown) return 'Meeting recorded';
  let cleaned = stripLinks(markdown);
  // Find content after "## Meeting Purpose" header
  const purposeMatch = cleaned.match(/## Meeting Purpose\s*\n+([^#]+)/i);
  if (purposeMatch) {
    // Get first non-empty line
    const firstLine = purposeMatch[1].trim().split('\n')[0].trim();
    return firstLine || 'Meeting recorded';
  }
  // Fallback: get first non-header line
  const lines = cleaned.split('\n').filter(line => !line.startsWith('#') && line.trim());
  return lines[0]?.trim() || 'Meeting recorded';
}

// Helper: Convert markdown to HTML and clean up (for notes)
function cleanSummaryHtml(markdown) {
  if (!markdown) return 'No summary available';
  let cleaned = stripLinks(markdown);
  // Remove "## Meeting Purpose" header
  cleaned = cleaned.replace(/^## Meeting Purpose\s*\n+/i, '');
  // Convert ## headers to bold
  cleaned = cleaned.replace(/^##+ (.+)$/gm, '<b>$1</b>');
  // Convert **bold** to <b>bold</b>
  cleaned = cleaned.replace(/\*\*([^*]+)\*\*/g, '<b>$1</b>');
  // Convert *italic* to <i>italic</i>
  cleaned = cleaned.replace(/\*([^*]+)\*/g, '<i>$1</i>');
  // Clean up excessive newlines
  cleaned = cleaned.replace(/\n{3,}/g, '\n\n');
  return cleaned.trim();
}

// Build the note content with HTML formatting (detailed)
const noteBody = `<b>Meeting ${formatDate(webhookData.scheduled_start_time)}</b>\n\n<b>Summary</b>\n${cleanSummaryHtml(webhookData.default_summary?.markdown_formatted)}\n\nMeeting recording: ${webhookData.share_url || 'N/A'}`;

// Build the comment content (SHORT version for conversation history)
const commentBody = `Meeting ${formatDate(webhookData.scheduled_start_time)}\n\nSummary: ${getBriefSummary(webhookData.default_summary?.markdown_formatted)}\n\nRecording: ${webhookData.share_url || 'N/A'}`;

// Return one item per external attendee
return externalAttendees.map(attendee => ({
  json: {
    attendee_email: attendee.email,
    attendee_name: attendee.name,
    meeting_title: webhookData.title,
    share_url: webhookData.share_url,
    note_body: noteBody,
    comment_body: commentBody,
    action_items: webhookData.action_items || [],
    meeting_date: webhookData.scheduled_start_time
  }
}));

// Extract conversationId from search results (existing conversation)
const conversations = $('Search Conversation').item.json.conversations;
if (conversations && conversations.length > 0) {
  return [{ json: { conversationId: conversations[0].id } }];
}
throw new Error('No conversation found');

// Extract conversationId from newly created conversation
const item = $input.first().json;
const conversationId = item.conversation?.id || item.id;
if (!conversationId) {
  throw new Error('Could not get conversationId from create response');
}
return [{ json: { conversationId } }];

const contactId = $('Search GHL Contact').item.json.contacts[0].id;
const actionItems = $('Parse External Attendees').item.json.action_items || [];
const meetingTitle = $('Parse External Attendees').item.json.meeting_title;

// Calculate due date (7 days from now at 17:00)
const dueDate = new Date();
dueDate.setDate(dueDate.getDate() + 7);
dueDate.setHours(17, 0, 0, 0);

return actionItems.map(item => ({
  json: {
    contactId: contactId,
    title: item.description,
    completed: item.completed || false,
    dueDate: dueDate.toISOString(),
    body: `<b>From meeting:</b> ${meetingTitle}`
  }
}));
